from __future__ import annotations

import base64
from functools import lru_cache

from PySide6.QtCore import Qt
from PySide6.QtGui import QPixmap


_PLAYED_BEFORE_PNG = """"""
_PREMADE_PNG = """"""


def _decode_png(encoded: str) -> QPixmap:
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(encoded), "PNG")
    return pixmap


@lru_cache(maxsize=16)
def played_before_pixmap(size: int = 16) -> QPixmap:
    source = _decode_png(_PLAYED_BEFORE_PNG)
    return source.scaled(
        int(size),
        int(size),
        Qt.AspectRatioMode.KeepAspectRatio,
        Qt.TransformationMode.SmoothTransformation,
    )


@lru_cache(maxsize=16)
def premade_pixmap(size: int = 17) -> QPixmap:
    source = _decode_png(_PREMADE_PNG)
    return source.scaled(
        int(size),
        int(size),
        Qt.AspectRatioMode.KeepAspectRatio,
        Qt.TransformationMode.SmoothTransformation,
    )
